Subscribe to ViewModel value changes and update the View on each update.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _label;
        private OneWayValue<int> _score = new();
        
        private void OnInitializedInternal(IViewModel viewModel)
        {
            OnScoreChanged(_score.Value);
            _score.Changed += OnScoreChanged;
        }
        
        private void OnDeinitializingInternal()
            _score.Changed -= OnScoreChanged;
        
        private void OnScoreChanged(int? value) =>
            _label.text = value.ToString();
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _score;
    }

Synchronize a slider with a ViewModel float property in both directions.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Slider _slider;
        [SerializeField] private TwoWayValue<float> _health;
        
        private void OnInitializedInternal(IViewModel viewModel)
        {
            _slider.value = _health.Value;
            _health.Changed += OnHealthChanged;
            _healthSlider.onValueChanged.AddListener(OnSliderChanged);
        }
        
        private void OnDeinitializingInternal()
        {
            _health.Changed -= OnHealthChanged;
            _healthSlider.onValueChanged.RemoveListener(OnSliderChanged);
        }
        
        private void OnHealthChanged(float? value) =>
            _slider.value = value ?? 0f;
        
        private void OnSliderChanged(float value) =>
            _health.Value = value;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _health;
    }

Read a ViewModel value exactly once at initialization time.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _label;
        private OneTimeValue<string> _name = new();
        
        partial void OnInitializedInternal(IViewModel viewModel) =>
            _label.text = _name.Value;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _name;
    }

Push an Inspector-set value to the ViewModel when binding is established.

